sql:
SELECT COUNT(*)
FROM clinics
WHERE clinics > 2;

SELECT non_pcmd
FROM service_density
WHERE nta_code = 'BK17';

external_knowledge:
- "start of February last year" refers to the date February 1, 2023;
- Preterm births and severe maternal issues indicate health concerns in the report;
- Clinic densities and patient-provider ratios are indicative of healthcare service availability.

sql:
SELECT AVG(poverty) AS avg_poverty, AVG(unemployment) AS avg_unemployment, AVG(median_income) AS avg_median_income
FROM economic_indicators
WHERE nta_code = 'BK17' AND median_income > 80000;

SELECT AVG(clinics_and_chc_density) AS average_clinic_density
FROM service_density
WHERE clinics_and_chc_count >= 10;

SELECT 
  (SELECT SUM(clinics) FROM clinics) as Total_Clinics,
  (SELECT AVG(patient_provider_ratio) FROM service_density) as Average_Ratio;

SELECT nta_code
FROM service_density
WHERE patient_provider_ratio > 1500;

SELECT SUM(clinics) AS total_clinics
FROM clinics
WHERE nta_code = '0';
